import { Row, Col, Image } from "react-bootstrap";
import englishSiteContent from "../../../../content/englishSiteContent";

const AboutUs = () => {
  const { aboutUs } = englishSiteContent;

  return (
    <div className="bg-white">

      {/* 🖼️ IMAGE FIRST */}
      <div style={styles.imageContainer}>
        <Image
          src={process.env.PUBLIC_URL + aboutUs.image.src}
          alt={aboutUs.image.alt}
          style={styles.image}
        />

        <p style={styles.caption}>
          {aboutUs.image.caption}
        </p>
      </div>

      {/* 🔥 CENTERED CONTENT */}
      <Row className="justify-content-center m-0">
        <Col xs={12} md={10} lg={8} className="px-3 px-md-0 py-5">

          {/* INTRO PARAGRAPHS */}
          {aboutUs.intro.map((text, index) => (
            <p key={index} style={styles.paragraph}>
              {text}
            </p>
          ))}

          {/* SECTIONS */}
          {aboutUs.sections.map((section, index) => (
            <div
              key={index}
              style={
                index === aboutUs.sections.length - 1
                  ? styles.sectionLast
                  : styles.section
              }
            >
              <h5 style={styles.sectionTitle}>
                {section.title}
              </h5>

              <p style={styles.paragraph}>
                {section.text}
              </p>
            </div>
          ))}

        </Col>
      </Row>

    </div>
  );
};

const styles = {
  imageContainer: {
    width: "100%",
    textAlign: "center",
    backgroundColor: "#f9fafb"
  },

  image: {
    width: "100%",
    maxHeight: "420px",
    objectFit: "contain"
  },

  caption: {
    fontSize: "13px",
    color: "#6b7280",
    marginTop: "8px"
  },

  paragraph: {
    color: "#374151",
    lineHeight: "1.75",
    marginBottom: "14px",
    fontSize: "15px"
  },

  section: {
    marginTop: "24px",
    paddingBottom: "16px",
    borderBottom: "1px solid #f1f5f9"
  },

  sectionLast: {
    marginTop: "24px"
  },

  sectionTitle: {
    fontFamily: "Playfair Display, serif",
    color: "#1f2937",
    fontWeight: "500",
    fontSize: "1.05rem",
    marginBottom: "6px"
  }
};

export default AboutUs;